const SERVIO_BUILD_VERSION = "claude-good-bess-db-pzu-github-cache-v3";
const nowIso = () => new Date().toISOString();
const json = (data, status = 200) => new Response(JSON.stringify(data, null, 2), {
  status,
  headers: {
    "content-type": "application/json; charset=utf-8",
    "cache-control": "no-store",
    "access-control-allow-origin": "*",
    "access-control-allow-methods": "GET,POST,OPTIONS",
    "access-control-allow-headers": "content-type,authorization,x-servio-token"
  }
});
const html = (body) => new Response(body, { status: 200, headers: { "content-type": "text/html; charset=utf-8", "cache-control": "no-store" } });
const js = (body) => new Response(body, { status: 200, headers: { "content-type": "text/javascript; charset=utf-8", "cache-control": "no-store" } });

function curve(day = "today") {
  const seed = day === "tomorrow" ? 23 : 11;
  const out = [];
  for (let i = 0; i < 96; i++) {
    const h = i / 4;
    const morning = 420 * Math.exp(-Math.pow(h - 8, 2) / 8);
    const evening = 580 * Math.exp(-Math.pow(h - 19, 2) / 7);
    const solarDip = -130 * Math.exp(-Math.pow(h - 13, 2) / 10);
    const noise = Math.sin(i * 1.71 + seed) * 42 + Math.cos(i * .37 + seed) * 18;
    const price = Math.max(80, Math.round(410 + morning + evening + solarDip + noise));
    out.push({ interval: i + 1, i, hour: h, label: String(Math.floor(h)).padStart(2, "0") + ":" + String((i % 4) * 15).padStart(2, "0"), price, priceLeiMwh: price, source: "SERVIO fallback OPCOM-like" });
  }
  return out;
}

const RO_BIDDING_ZONE_EIC = "10YRO-TEL------P";
const DEFAULT_EUR_RON = 4.97;
const OPCOM_GITHUB_CACHE_DEFAULT_URL = "https://raw.githubusercontent.com/mrshoby/servio/main/data/opcom/pzu/latest.json";
function bucharestYmd(offsetDays = 0) {
  const now = new Date();
  const parts = new Intl.DateTimeFormat("en-CA", { timeZone: "Europe/Bucharest", year: "numeric", month: "2-digit", day: "2-digit" }).formatToParts(now);
  const y = Number(parts.find(p => p.type === "year").value);
  const m = Number(parts.find(p => p.type === "month").value);
  const d = Number(parts.find(p => p.type === "day").value);
  const utc = new Date(Date.UTC(y, m - 1, d + offsetDays, 0, 0, 0));
  return utc.toISOString().slice(0, 10);
}
function ymdForDayParam(day) {
  const v = String(day || "today").toLowerCase();
  if (/^\d{4}-\d{2}-\d{2}$/.test(v)) return v;
  return bucharestYmd(v.includes("tomorrow") || v.includes("maine") || v.includes("mâine") ? 1 : 0);
}
function entsoeDateCompact(ymd) { return ymd.replaceAll("-", ""); }
function nextYmd(ymd) { const d = new Date(ymd + "T00:00:00Z"); d.setUTCDate(d.getUTCDate() + 1); return d.toISOString().slice(0, 10); }
function labelForInterval(i) { const h = Math.floor(i / 4); const m = (i % 4) * 15; return String(h).padStart(2, "0") + ":" + String(m).padStart(2, "0"); }
function normalizeRoNumber(v) {
  const s = String(v || "").trim().replace(/\s/g, "");
  if (!s) return NaN;
  return Number(s.replace(/\./g, "").replace(",", "."));
}
function recordsFromPrices(prices, meta = {}) {
  const rows = prices.slice(0, 96).map((price, i) => ({ interval: i + 1, i, hour: i / 4, label: labelForInterval(i), price: Math.round(Number(price)), priceLeiMwh: Math.round(Number(price)), source: meta.source || "Day-Ahead PZU" }));
  const vals = rows.map(r => r.price);
  return { ok: true, currency: "Lei/MWh", granularity: "15m", intervals: rows.length, min: Math.min(...vals), max: Math.max(...vals), avg: Math.round(vals.reduce((a,b)=>a+b,0)/vals.length), records: rows, ...meta, generatedAtUtc: nowIso() };
}
function fallbackDayAhead(day, source, warning) {
  const records = curve(day);
  const prices = records.map(r => r.price);
  return { ok: true, source, sourceMode: "fallback-local", warning, currency: "Lei/MWh", granularity: "15m", intervals: records.length, min: Math.min(...prices), max: Math.max(...prices), avg: Math.round(prices.reduce((a,b)=>a+b,0)/prices.length), records, generatedAtUtc: nowIso() };
}

function withNoCacheParam(u) {
  try {
    const x = new URL(u);
    x.searchParams.set("_", String(Date.now()));
    return x.toString();
  } catch { return u; }
}
function githubCacheUrlForDay(day = "today", env = {}) {
  const configured = String(env.OPCOM_GITHUB_CACHE_URL || OPCOM_GITHUB_CACHE_DEFAULT_URL);
  const deliveryDay = ymdForDayParam(day);
  if (String(day || "today").toLowerCase() === "today") return configured;
  if (configured.includes("latest.json")) return configured.replace(/latest\.json(\?.*)?$/, deliveryDay + ".json");
  return configured;
}
async function fetchOpcomDayAheadGithubCache(day = "today", env = {}) {
  const deliveryDay = ymdForDayParam(day);
  const sourceUrl = githubCacheUrlForDay(day, env);
  const res = await fetch(withNoCacheParam(sourceUrl), { headers: { "accept": "application/json,text/plain,*/*", "user-agent": "SERVIO/OPCOM-GitHub-Cache" } });
  if (!res.ok) throw new Error("OPCOM GitHub cache HTTP " + res.status);
  const data = await res.json();
  if (!data || data.ok === false) throw new Error("OPCOM GitHub cache not ready" + (data && data.error ? ": " + data.error : ""));
  const sourceRecords = Array.isArray(data.records) ? data.records : [];
  if (sourceRecords.length < 90) throw new Error("OPCOM GitHub cache returned " + sourceRecords.length + "/96 intervals");
  const prices = sourceRecords.slice(0, 96).map(r => Number(r.priceLeiMwh ?? r.price ?? r.value ?? r.ROPEX_DAM_15min)).filter(Number.isFinite);
  if (prices.length !== 96) throw new Error("OPCOM GitHub cache has missing numeric prices: " + prices.length + "/96");
  return recordsFromPrices(prices, { source: "OPCOM PZU / ROPEX_DAM_15min", sourceMode: "external-cache-github", sourceUrl, deliveryDay: data.deliveryDay || deliveryDay, cacheUpdatedAtUtc: data.updatedAtUtc || data.generatedAtUtc || null, cacheGeneratedBy: data.generatedBy || "GitHub Actions" });
}
async function fetchOpcomDayAheadPreferred(day = "today", env = {}) {
  try { return await fetchOpcomDayAheadGithubCache(day, env); }
  catch (githubError) {
    try { return await fetchOpcomDayAheadExternal(day); }
    catch (directError) {
      const g = githubError && githubError.message ? githubError.message : String(githubError);
      const d = directError && directError.message ? directError.message : String(directError);
      throw new Error("GitHub cache: " + g + " | OPCOM direct: " + d);
    }
  }
}

async function fetchOpcomDayAheadExternal(day = "today") {
  const deliveryDay = ymdForDayParam(day);
  const sourceUrl = "https://www.opcom.ro/grafice-ip-raportPIP-si-volumTranzactionat/ro";
  const res = await fetch(sourceUrl, { headers: { "user-agent": "SERVIO/DayAheadLiveFetch", "accept": "text/html,application/xhtml+xml,text/plain,*/*" } });
  if (!res.ok) throw new Error("OPCOM HTTP " + res.status);
  const html = await res.text();
  const text = html.replace(/<script[\s\S]*?<\/script>/gi, " ").replace(/<style[\s\S]*?<\/style>/gi, " ").replace(/<[^>]+>/g, " ").replace(/&nbsp;|&#160;/g, " ").replace(/\s+/g, " ");
  const matches = [...text.matchAll(/Romania\s+(\d{1,2})\s+(-?\d{1,3}(?:\.\d{3})*,\d+|-?\d+,\d+)/g)];
  const map = new Map();
  for (const m of matches) {
    const idx = Number(m[1]);
    const price = normalizeRoNumber(m[2]);
    if (idx >= 1 && idx <= 96 && Number.isFinite(price) && !map.has(idx)) map.set(idx, price);
  }
  if (map.size < 90) throw new Error("OPCOM parser returned " + map.size + " intervals, expected ~96");
  const prices = Array.from({ length: 96 }, (_, i) => map.get(i + 1)).filter(v => Number.isFinite(v));
  if (prices.length !== 96) throw new Error("OPCOM has missing intervals: " + prices.length + "/96");
  return recordsFromPrices(prices, { source: "OPCOM PZU / ROPEX_DAM_15min", sourceMode: "external-live", sourceUrl, deliveryDay });
}
async function fetchEntsoeDayAheadExternal(day = "today", env = {}) {
  const token = env.ENTSOE_API_TOKEN || env.ENTSOE_TOKEN || env.securityToken;
  if (!token) throw new Error("ENTSOE_API_TOKEN lipsește din Cloudflare secrets");
  const deliveryDay = ymdForDayParam(day);
  const periodStart = entsoeDateCompact(deliveryDay) + "0000";
  const periodEnd = entsoeDateCompact(nextYmd(deliveryDay)) + "0000";
  const apiUrl = "https://web-api.tp.entsoe.eu/api?" + new URLSearchParams({ securityToken: token, documentType: "A44", in_Domain: RO_BIDDING_ZONE_EIC, out_Domain: RO_BIDDING_ZONE_EIC, periodStart, periodEnd }).toString();
  const res = await fetch(apiUrl, { headers: { "accept": "application/xml,text/xml,*/*" } });
  if (!res.ok) throw new Error("ENTSO-E HTTP " + res.status);
  const xml = await res.text();
  if (/No matching data|Acknowledgement_MarketDocument/i.test(xml)) throw new Error("ENTSO-E nu a returnat prețuri A44 pentru " + deliveryDay);
  const pointBlocks = [...xml.matchAll(/<[^>]*Point[^>]*>([\s\S]*?)<\/[^>]*Point>/g)].map(m => m[1]);
  const raw = [];
  for (const block of pointBlocks) {
    const pos = block.match(/<[^>]*position[^>]*>\s*(\d+)\s*<\/[^>]*position>/i);
    const price = block.match(/<[^>]*price\.amount[^>]*>\s*(-?\d+(?:\.\d+)?)\s*<\/[^>]*price\.amount>/i);
    if (pos && price) raw.push({ position: Number(pos[1]), eur: Number(price[1]) });
  }
  if (!raw.length) throw new Error("ENTSO-E parser: 0 price points");
  raw.sort((a,b) => a.position - b.position);
  let eurPrices = raw.map(p => p.eur);
  if (eurPrices.length === 24) eurPrices = eurPrices.flatMap(v => [v, v, v, v]);
  if (eurPrices.length < 90) throw new Error("ENTSO-E returned " + eurPrices.length + " intervals, expected 24 or 96");
  const eurRon = Number(env.EUR_RON || DEFAULT_EUR_RON);
  const leiPrices = eurPrices.slice(0, 96).map(v => v * eurRon);
  return recordsFromPrices(leiPrices, { source: "ENTSO-E Transparency A44 / Romania", sourceMode: "external-live", sourceUrl: "https://web-api.tp.entsoe.eu/api", deliveryDay, originalCurrency: "EUR/MWh", eurRon, biddingZone: RO_BIDDING_ZONE_EIC });
}


